import React, { useState, useEffect } from 'react';
import { fetchExpenses, addExpense, deleteExpense } from './services/api';
import Dashboard from './components/Dashboard';
import ExpenseForm from './components/ExpenseForm';
import ExpenseList from './components/ExpenseList';
import { Activity, PlusCircle, LayoutDashboard } from 'lucide-react';

function App() {
  const [expenses, setExpenses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [adding, setAdding] = useState(false);
  const [notification, setNotification] = useState(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const data = await fetchExpenses();
      setExpenses(data);
    } catch (err) {
      showNotification('Failed to load expenses', 'error');
    } finally {
      setLoading(false);
    }
  };

  const handleAddExpense = async (expense) => {
    setAdding(true);
    try {
      const newExp = await addExpense(expense);
      setExpenses([newExp, ...expenses]);
      showNotification('Expense added successfully!', 'success');
    } catch (err) {
      showNotification('Failed to add expense', 'error');
    } finally {
      setAdding(false);
    }
  };

  const handleDeleteExpense = async (id) => {
    try {
      await deleteExpense(id);
      setExpenses(expenses.filter(e => e.id !== id));
      showNotification('Expense deleted', 'success');
    } catch (err) {
      showNotification('Failed to delete expense', 'error');
    }
  };

  const showNotification = (message, type) => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 3000);
  };

  return (
    <div className="min-h-screen bg-surface font-inter text-on-surface flex flex-col md:flex-row">
      {/* Sidebar Mockup */}
      <aside className="w-full md:w-64 bg-surface-container-lowest border-r border-outline-variant/20 p-6 md:min-h-screen sticky top-0 z-10 glass-effect">
        <h1 className="text-2xl font-manrope font-bold text-primary flex items-center gap-2 mb-10">
          <Activity className="w-8 h-8 text-primary" />
          The Fluid Auditor
        </h1>
        <nav className="flex flex-col gap-4">
          <a href="#" className="flex items-center gap-3 text-primary font-semibold text-sm bg-surface-container-low px-4 py-3 rounded-2xl transition-colors">
            <LayoutDashboard className="w-5 h-5" />
            Dashboard
          </a>
          <a href="#add" className="flex items-center gap-3 text-on-surface-variant font-medium text-sm px-4 py-3 rounded-2xl hover:bg-surface-container-low/50 transition-colors">
            <PlusCircle className="w-5 h-5" />
            Add Expense
          </a>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-6 md:p-10 lg:p-12 max-w-6xl mx-auto space-y-12">
        {/* Notification Toast */}
        {notification && (
          <div className="fixed top-6 right-6 z-50 animate-in fade-in slide-in-from-top-4">
            <div className={`px-6 py-4 rounded-2xl shadow-ambient backdrop-blur-md flex items-center gap-3 border ${notification.type === 'error' ? 'bg-tertiary-container/90 border-tertiary text-tertiary-fixed' : 'bg-surface-container-lowest/90 border-secondary text-secondary'}`}>
              <span className="font-semibold">{notification.message}</span>
            </div>
          </div>
        )}

        <header>
          <h2 className="text-3xl font-manrope font-extrabold tracking-tight">Overview</h2>
          <p className="text-on-surface-variant mt-2">Monitor your financial intelligence.</p>
        </header>

        {loading ? (
          <div className="flex justify-center py-20">
            <div className="animate-spin rounded-full h-12 w-12 border-4 border-primary border-t-transparent"></div>
          </div>
        ) : (
          <>
            <Dashboard expenses={expenses} />

            <div className="grid grid-cols-1 xl:grid-cols-3 gap-8 items-start">
              <div className="xl:col-span-1 sticky top-6" id="add">
                <ExpenseForm onAdd={handleAddExpense} isLoading={adding} />
              </div>
              <div className="xl:col-span-2">
                <ExpenseList expenses={expenses} onDelete={handleDeleteExpense} />
              </div>
            </div>
          </>
        )}
      </main>
    </div>
  );
}

export default App;
